1	# WebSocket Protocol
2	
3	Source: plan-draft3.md §Protocol Layer, §Client Render Model, §Web
4	Dashboard (D17, D18, D19, D20, D42, D49, D50).
5	
6	Single multiplexed socket per client. Server binds 127.0.0.1 (D57).
7	Protocol version is pinned in every frame (`v: 1`); mismatches are
8	refused at `hello` exchange. There is no authentication (D57).
9	
10	---
11	
12	## 1. Envelope
13	
14	### Server → client
15	
16	```ts
17	interface ServerFrame {
18	  v: 1;
19	  type: ServerFrameType;
20	  workflowId?: string;  // absent on "hello", "pong", "notice" (global)
21	  sessionId?: string;   // absent on workflow-scope frames
22	  seq: number;          // monotonic per session; 0 on non-session frames
23	  ts: string;           // ISO-8601 UTC
24	  payload: unknown;     // type-specific; see §2
25	}
26	```
27	
28	`seq` rules:
29	- Per-session: starts at 1 for the first frame carrying that
30	  `sessionId`, increments by 1, never skips.
31	- Non-session frames use `seq: 0`.
32	- Backfill replays preserve original `seq`.
33	
34	### Client → server
35	
36	```ts
37	interface ClientFrame {
38	  v: 1;
39	  type: ClientFrameType;
40	  id: string;    // client-generated commandId (uuid); idempotency key
41	  payload: unknown;
42	}
43	```
44	
45	---
46	
47	## 2. Server frame types
48	
49	```ts
50	type ServerFrameType =
51	  | "hello"
52	  | "workflow.snapshot"
53	  | "workflow.update"
54	  | "workflow.index.update"
55	  | "item.state"
56	  | "item.data"
57	  | "stage.started"
58	  | "stage.complete"
59	  | "session.started"
60	  | "session.ended"
61	  | "stream.text"
62	  | "stream.thinking"
63	  | "stream.tool_use"
64	  | "stream.tool_result"
65	  | "stream.usage"
66	  | "stream.system_notice"
67	  | "prepost.command.started"
68	  | "prepost.command.output"
69	  | "prepost.command.ended"
70	  | "notice"
71	  | "error"
72	  | "pong"
73	  | "backfill.truncated";
74	```
75	
76	### 2.1 `hello`
77	Sent once on connect before any other frame.
78	
79	```ts
80	interface HelloPayload {
81	  serverVersion: string;   // yoke server semver
82	  protocolVersion: 1;
83	  capabilities: string[];  // e.g. ["backfill", "keepalive", "prepost"]
84	  heartbeatIntervalMs: number;
85	}
86	```
87	
88	Client MUST disconnect if `protocolVersion !== 1`.
89	
90	### 2.2 `workflow.snapshot`
91	A full workflow state dump, sent in response to `subscribe`. Includes
92	item rows (with state and data separated per Issue 3), stage info,
93	live session rows, `recoveryState` if set, `githubState`.
94	
95	```ts
96	interface WorkflowSnapshotPayload {
97	  workflow: {
98	    id: string;
99	    name: string;
100	    status: string;        // state-machine label
101	    currentStage: string | null;  // stage id (Issue 1)
102	    createdAt: string;
103	    recoveryState?: RecoveryState | null;
104	    githubState?: GithubState | null;
105	  };
106	  stages: StageProjection[];         // ordered stage list (Issue 1)
107	  items: ItemProjection[];           // item state + display fields (Issue 2, 3)
108	  activeSessions: SessionProjection[];
109	  pendingAttention: PendingAttention[];
110	}
111	
112	interface StageProjection {
113	  id: string;
114	  run: "once" | "per-item";
115	  phases: string[];
116	  status: "pending" | "in_progress" | "complete" | "blocked";
117	  needsApproval: boolean;
118	}
119	
120	interface ItemProjection {
121	  id: string;
122	  stageId: string;
123	  state: ItemStateProjection;        // harness state (Issue 3)
124	  displayTitle: string | null;       // resolved from items_display config
125	  displaySubtitle: string | null;
126	}
127	
128	interface ItemStateProjection {
129	  status: string;
130	  currentPhase: string | null;
131	  retryCount: number;
132	  blockedReason: string | null;
133	}
134	```
135	
136	Item user data (the opaque blob) is NOT included in the snapshot by
137	default — it can be large. The dashboard requests it on demand via
138	`item.data` frames when the user opens an item detail view (Issue 3).
139	
140	### 2.3 `workflow.update` / `item.state` / `item.data`
141	`workflow.update`: partial updates for changed workflow-level fields.
142	
143	`item.state` (replaces `feature.update`): carries the item ID and
144	changed harness-state fields only (status, currentPhase, retryCount,
145	blockedReason). Does NOT include user data (Issue 3).
146	
147	```ts
148	interface ItemStatePayload {
149	  itemId: string;
150	  stageId: string;
151	  state: Partial<ItemStateProjection>;
152	}
153	```
154	
155	`item.data`: carries the opaque user data blob for a specific item.
156	Sent on demand when the dashboard requests it, not pushed automatically.
157	
158	```ts
159	interface ItemDataPayload {
160	  itemId: string;
161	  data: unknown;  // opaque JSON blob from items.data (Issue 2)
162	}
163	```
164	
165	### 2.3a `stage.started` / `stage.complete` (Issue 1)
166	
167	```ts
168	interface StageStartedPayload {
169	  stageId: string;
170	  run: "once" | "per-item";
171	  itemCount?: number;  // for per-item stages
172	}
173	interface StageCompletePayload {
174	  stageId: string;
175	  nextStageId: string | null;
176	  needsApproval: boolean;  // whether next stage requires approval
177	  itemSummary?: {
178	    complete: number;
179	    blocked: number;
180	    abandoned: number;
181	  };
182	}
183	```
184	
185	### 2.4 `workflow.index.update`
186	Lightweight update for the sidebar list — id, name, status,
187	`updatedAt`, `unreadEvents` — never contains stream content. Sent to
188	every connected client regardless of subscription (§Subscription model).
189	
190	### 2.5 `session.started` / `session.ended`
191	
192	```ts
193	interface SessionStartedPayload {
194	  sessionId: string;
195	  phase: string;
196	  attempt: number;
197	  startedAt: string;
198	  parentSessionId?: string | null;
199	}
200	interface SessionEndedPayload {
201	  sessionId: string;
202	  endedAt: string;
203	  exitCode: number | null;
204	  statusFlags: Record<string, number | boolean>;
205	  reason: "ok" | "fail" | "cancelled" | "rate_limited" | "tainted";
206	}
207	```
208	
209	### 2.6 `stream.*` — normalized render model (D18)
210	
211	Server emits **normalized** events, not raw stream-json. See
212	`protocol-stream-json.md` for the parser that produces these.
213	
214	```ts
215	interface StreamText {
216	  sessionId: string;
217	  blockId: string;           // stable per content block
218	  textDelta: string;         // accumulates on client
219	  final?: boolean;           // true on content_block_stop
220	}
221	interface StreamThinking {
222	  sessionId: string;
223	  blockId: string;
224	  textDelta: string;
225	  final?: boolean;
226	}
227	interface StreamToolUse {
228	  sessionId: string;
229	  toolUseId: string;
230	  name: string;
231	  input: unknown;
232	  status: "pending" | "running";
233	}
234	interface StreamToolResult {
235	  sessionId: string;
236	  toolUseId: string;
237	  status: "ok" | "error";
238	  output: unknown;
239	}
240	interface StreamUsage {
241	  sessionId: string;
242	  inputTokens: number;
243	  outputTokens: number;
244	  cacheCreationInputTokens: number;
245	  cacheReadInputTokens: number;
246	  rawUsage: unknown;
247	}
248	interface StreamSystemNotice {
249	  sessionId?: string;
250	  severity: "info" | "warn" | "error";
251	  source:
252	    | "harness"
253	    | "stderr"
254	    | "heartbeat"
255	    | "rate_limit"
256	    | "hook"
257	    | "recovery";
258	  message: string;
259	  extra?: unknown;
260	}
261	```
262	
263	### 2.7 `prepost.command.*` (D50 frame additions)
264	
265	```ts
266	interface PrepostCommandStarted {
267	  runId: number;              // prepost_runs.id
268	  phase: string;
269	  when: "pre" | "post";
270	  name: string;
271	  argv: string[];
272	  startedAt: string;
273	}
274	interface PrepostCommandOutput {
275	  runId: number;
276	  stream: "stdout" | "stderr";
277	  chunk: string;              // UTF-8; caller truncates per render model
278	}
279	interface PrepostCommandEnded {
280	  runId: number;
281	  exitCode: number;
282	  action: unknown;            // ResolvedAction from pre-post-action-grammar.md
283	  endedAt: string;
284	}
285	```
286	
287	Frames for `post:` commands are rendered in the live pane as
288	`SystemNotice` rows, left-rule-accented, per D50 ("same rendering path
289	as SystemNotice").
290	
291	### 2.8 `notice` / `error`
292	
293	```ts
294	interface NoticePayload {
295	  severity: "info" | "requires_attention";
296	  kind: string;
297	  message: string;
298	  persistedAttentionId?: number;
299	}
300	interface ErrorPayload {
301	  code: string;    // "PROTOCOL_MISMATCH", "SUBSCRIPTION_LIMIT", ...
302	  message: string;
303	  commandId?: string;
304	}
305	```
306	
307	### 2.9 `pong`
308	Response to `ping`, carries the `id` of the ping frame.
309	
310	### 2.10 `backfill.truncated`
311	
312	```ts
313	interface BackfillTruncatedPayload {
314	  workflowId: string;
315	  sinceSeq: number;
316	  minAvailableSeq: number;
317	  httpFetchUrl: string;       // GET /api/sessions/:id/log?sinceSeq=...&limit=...
318	}
319	```
320	
321	---
322	
323	## 3. Client frame types
324	
325	```ts
326	type ClientFrameType =
327	  | "subscribe"
328	  | "unsubscribe"
329	  | "control"
330	  | "ack"
331	  | "ping";
332	
333	interface SubscribePayload {
334	  workflowId: string;
335	  sinceSeq?: number;
336	}
337	interface UnsubscribePayload {
338	  workflowId: string;
339	}
340	interface ControlPayload {
341	  workflowId: string;
342	  action:
343	    | "pause"
344	    | "resume"
345	    | "cancel"
346	    | "skip"
347	    | "rerun-phase"
348	    | "inject-context"
349	    | "unblock"
350	    | "retry"
351	    | "approve-stage";       // Issue 1: approve a stage with needs_approval
352	  itemId?: string;            // renamed from featureId (Issue 2)
353	  stageId?: string;           // for approve-stage action (Issue 1)
354	  extra?: unknown;            // e.g. inject-context text
355	}
356	interface AckPayload {
357	  lastAppliedSeq: number;
358	  sessionId: string;
359	}
360	interface PingPayload {
361	  clientTs: string;
362	}
363	```
364	
365	Server is idempotent on `ClientFrame.id`: a repeated id within 5 min
366	returns the previous response.
367	
368	---
369	
370	## 4. Lifecycle
371	
372	```
373	client → ws:/stream
374	server → hello                             (seq=0)
375	client → subscribe { workflowId, sinceSeq? }
376	server → workflow.snapshot                 (seq=0)
377	server → (backfill frames)                 (seq=original)
378	   ...  or ...
379	server → backfill.truncated                (seq=0)
380	         then snapshot only, no replay
381	server → (live frames)                     (seq++)
382	client → ack { lastAppliedSeq }            (opportunistic)
383	client → unsubscribe { workflowId }
384	server → (stops sending workflow-scoped frames)
385	```
386	
387	- Multiple subscriptions are interleaved on one socket. `workflowId`
388	  discriminates.
389	- Subscription cap is 4 concurrent streaming workflows per client
390	  (plan-draft3 §Subscription model). Extras receive only
391	  `workflow.index.update` and must fall back to polled snapshots.
392	- `ack` is advisory; the server never waits for it. Its purpose is to
393	  trim retained backfill buffers when all subscribers have acknowledged
394	  past a seq.
395	
396	---
397	
398	## 5. Reconnect / backfill flow
399	
400	1. Client reconnects and sends `subscribe { workflowId, sinceSeq: N }`.
401	2. Server loads session log index and computes the earliest retained
402	   seq for each active session.
403	3. If `N ≥ earliestRetained − 1`, server replays frames `N+1..latest`
404	   in original order with original `seq`, then switches to live.
405	4. Else server emits `backfill.truncated` with a URL to page the full
406	   log. Client fetches HTTP, merges into its virtualized list, then
407	   switches to live.
408	5. Dedupe: client keeps a `(sessionId, seq)` high-water mark and drops
409	   anything `seq <= lastApplied` (plan-draft3 §Backfill on reconnect).
410	
411	---
412	
413	## 6. Sequence rules & invariants
414	
415	- `stream.text` deltas for a given `blockId` always increase in seq
416	  until one of them has `final: true`; thereafter no new delta arrives
417	  for that block.
418	- `stream.tool_result` always arrives after the matching
419	  `stream.tool_use` for the same `toolUseId`. If a reconnect drops the
420	  `tool_use`, the client MUST treat an orphan `tool_result` as an
421	  error and request a snapshot.
422	- `prepost.command.ended` always follows `prepost.command.started`
423	  with the same `runId`. A dropped start invalidates the run row — the
424	  client requests a snapshot.
425	- `session.ended` is the terminal frame for a given `sessionId`; no
426	  `stream.*` frame for that session may arrive afterward.
427	
428	---
429	
430	## 7. HTTP companion endpoints
431	
432	Used by backfill and by flows the WS doesn't carry:
433	
434	| Method + path | Purpose |
435	|---|---|
436	| `GET /api/workflows?status=&q=&before=&limit=` | keyset pagination (D47) |
437	| `GET /api/workflows/:id/timeline` | merged SQLite events + JSONL (§Obs, D34) |
438	| `GET /api/sessions/:id/log?sinceSeq=&limit=` | paged stream-json fetch (D48a) |
439	| `GET /api/workflows/:id/usage?groupBy=feature|phase|profile|session` | token aggregates |
440	| `GET /api/workflows/:id/usage/timeseries?bucket=hour|day` | usage timeseries |
441	| `POST /api/workflows/:id/control` | idempotent manual control (mirrors WS `control`) |
442	| `POST /api/workflows/:id/attention/:attentionId/ack` | clear pending attention |
443	
444	All endpoints bind 127.0.0.1 (D57).
445	
446	---
447	
448	## 8. TypeScript type definition block (authoritative)
449	
450	```ts
451	export type ServerFrameType =
452	  | "hello"
453	  | "workflow.snapshot"
454	  | "workflow.update"
455	  | "workflow.index.update"
456	  | "item.state"
457	  | "item.data"
458	  | "stage.started"
459	  | "stage.complete"
460	  | "session.started"
461	  | "session.ended"
462	  | "stream.text"
463	  | "stream.thinking"
464	  | "stream.tool_use"
465	  | "stream.tool_result"
466	  | "stream.usage"
467	  | "stream.system_notice"
468	  | "prepost.command.started"
469	  | "prepost.command.output"
470	  | "prepost.command.ended"
471	  | "notice"
472	  | "error"
473	  | "pong"
474	  | "backfill.truncated";
475	
476	export type ClientFrameType =
477	  | "subscribe"
478	  | "unsubscribe"
479	  | "control"
480	  | "ack"
481	  | "ping";
482	
483	export interface ServerFrame<T = unknown> {
484	  v: 1;
485	  type: ServerFrameType;
486	  workflowId?: string;
487	  sessionId?: string;
488	  seq: number;
489	  ts: string;
490	  payload: T;
491	}
492	
493	export interface ClientFrame<T = unknown> {
494	  v: 1;
495	  type: ClientFrameType;
496	  id: string;
497	  payload: T;
498	}
499	
500	export interface RecoveryState {
501	  recoveredAt: string;
502	  priorStatus: string;
503	  resumeMethod: "continue" | "fresh";
504	  uncommittedChanges: boolean;
505	  lastKnownSessionId: string | null;
506	}
507	
508	export interface GithubState {
509	  status:
510	    | "disabled"
511	    | "unconfigured"
512	    | "idle"
513	    | "creating"
514	    | "created"
515	    | "failed";
516	  prNumber?: number;
517	  prUrl?: string;
518	  prState?: "open" | "merged" | "closed";
519	  error?: string;
520	  lastCheckedAt?: string;
521	}
522	
523	export interface PendingAttention {
524	  id: number;
525	  kind: string;
526	  payload: unknown;
527	  createdAt: string;
528	}
529	```
530	
531	---
532	
533	## 9. Error handling
534	
535	- Server closes the socket with code 4001 on protocol version mismatch.
536	- Server closes with 4002 on subscription cap exceeded after sending
537	  `error { code: "SUBSCRIPTION_LIMIT" }`.
538	- Malformed client frame → `error { code: "BAD_FRAME" }`, socket stays
539	  open.
540	- Server-side fatal → `error { code: "INTERNAL" }` then close.
541	- Client SHOULD reconnect with exponential backoff capped at 30 s and
542	  resume with `subscribe { sinceSeq }` for any active workflow.
543

