1	/**
2	 * HTTP companion endpoint tests — feat-fastify-ws.
3	 *
4	 * Covers AC-5: all HTTP endpoints from protocol-websocket.md §7 return the
5	 * correct 2xx shape for valid input, 404 for unknown workflow/session, 400
6	 * for bad query params.
7	 *
8	 * Uses fastify.inject() for fast, socketless HTTP testing. Real SQLite +
9	 * migrations; no mocks.
10	 */
11	
12	import * as fs from 'fs';
13	import * as os from 'os';
14	import * as path from 'path';
15	import { afterEach, beforeEach, describe, expect, it } from 'vitest';
16	import { createServer, type ServerHandle } from '../../src/server/api/server.js';
17	import { openDbPool } from '../../src/server/storage/db.js';
18	import { applyMigrations } from '../../src/server/storage/migrate.js';
19	
20	// ---------------------------------------------------------------------------
21	// Setup / teardown
22	// ---------------------------------------------------------------------------
23	
24	let tmpDir: string;
25	let db: ReturnType<typeof openDbPool>;
26	let handle: ServerHandle;
27	
28	beforeEach(async () => {
29	  tmpDir = await fs.promises.mkdtemp(path.join(os.tmpdir(), 'yoke-http-f-'));
30	  db = openDbPool(path.join(tmpDir, 'test.db'));
31	
32	  const migrationsDir = new URL(
33	    '../../src/server/storage/migrations/',
34	    import.meta.url,
35	  ).pathname;
36	  await applyMigrations(db.writer, migrationsDir);
37	
38	  handle = await createServer(db);
39	  // Use inject() — no listen() needed for HTTP tests.
40	  await handle.fastify.ready();
41	});
42	
43	afterEach(async () => {
44	  await handle.fastify.close();
45	  db.close();
46	  await fs.promises.rm(tmpDir, { recursive: true, force: true });
47	});
48	
49	// ---------------------------------------------------------------------------
50	// Helpers
51	// ---------------------------------------------------------------------------
52	
53	interface InjectResult {
54	  statusCode: number;
55	  body: unknown;
56	}
57	
58	async function inject(
59	  method: string,
60	  url: string,
61	  body?: object,
62	): Promise<InjectResult> {
63	  const res = await handle.fastify.inject({
64	    method: method as 'GET' | 'POST' | 'PUT' | 'DELETE',
65	    url,
66	    ...(body ? { payload: JSON.stringify(body), headers: { 'content-type': 'application/json' } } : {}),
67	  });
68	  return {
69	    statusCode: res.statusCode,
70	    body: JSON.parse(res.body) as unknown,
71	  };
72	}
73	
