  statusCode: number;
  body: unknown;
}

async function inject(
  method: string,
  url: string,
  body?: object,
): Promise<InjectResult> {
  const res = await handle.fastify.inject({
    method: method as 'GET' | 'POST' | 'PUT' | 'DELETE',
    url,
    ...(body ? { payload: JSON.stringify(body), headers: { 'content-type': 'application/json' } } : {}),
